@SetSkitCamera,GL_R001_000,-2,-2,0.6
@SetSkitCast,主人公,GL_R001_000,-3,-1,45,0
@SetSkitCast,スカーレット,GL_R001_000,-1,-3,-135,0
@HideSkitCast,彩葉
@EndSkit



@StartSkit,トレーニング終わりのスカーレット
@PlaySkitCastAction,スカーレット,Action0
@EndSkit


@StartSkit,元気に返事するスカーレット
